#include <stdio.h>
#include <pthread.h>

static int total = 0;

typedef struct { int amount; } arg_t;

void *worker(void *arg) {
    int amount = ((arg_t *)arg)->amount;
    // your code here: safely add amount to total
    (void)amount;
    return NULL;
}

int main(void) {
    arg_t args[4] = {{10}, {20}, {30}, {40}};
    pthread_t threads[4];
    for (int i = 0; i < 4; i++) {
        pthread_create(&threads[i], NULL, worker, &args[i]);
    }
    for (int i = 0; i < 4; i++) {
        pthread_join(threads[i], NULL);
    }
    printf("Total: %d\n", total);
    return 0;
}
